The task_assignments table stores information about the tasks assigned to team members, including the member_id, task_id, and assignment_date; 
The time_logs table stores records of time spent on tasks, including the task_id and hours_spent; 
The member with id 1 is the team member of interest.

sql:
SELECT SUM(hours_spent) AS total_hours_spent
FROM time_logs
WHERE member_id IN (
  SELECT tm.member_id
  FROM team_members tm
  JOIN teams t ON tm.team_id = t.team_id
  WHERE t.project_id = (
    SELECT project_id FROM projects WHERE project_name = 'Bravo'
  )
  AND tm.member_id IN (
    SELECT member_id FROM member_roles WHERE role_id = (
      SELECT role_id FROM roles WHERE role_name = 'Team Lead'
    )
  )
);

SELECT COUNT(DISTINCT member_id)
FROM task_assignments
WHERE task_id IN (SELECT task_id FROM tasks WHERE project_id = 1);

SELECT task_id, task_description
FROM tasks
WHERE owner_id IS NULL AND project_id = (SELECT project_id FROM projects WHERE project_name = 'Project Bravo');
